static constexpr uint32_t MAX_UB_BYTES = 192 * 1024;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    LogSoftmaxCustomTilingData tiling;

    const gert::Shape *shape = context->GetInputShape(0);
    uint32_t height = static_cast<uint32_t>(shape->GetDim(0));
    uint32_t width  = static_cast<uint32_t>(shape->GetDim(1));
    uint32_t totalLength = height * width;

    // Block dim: each block processes a subset of rows.
    // For simplicity, assign rows to blocks in round-robin.
    const uint32_t blockDim = (height < 24) ? height : 24;
    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_height(height);
    tiling.set_width(width);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

